() => {
  const addHost = document.querySelector("otto-web-tool-bar-toggle-button[data-qa-id='addBtn']");
  const addBtn = addHost?.querySelector("button[data-qa-id='toolBarButtonToggle']");

  // Ocultar botones hermanos para evitar ruido visual.
  document.querySelectorAll("otto-web-tool-bar-toggle-button").forEach((host) => {
    if (host !== addHost) {
      host.style.display = 'none';
      const b = host.querySelector("button[data-qa-id='toolBarButtonToggle']");
      if (b) b.style.display = 'none';
    }
  });

  const tip = Array.from(document.querySelectorAll('gs-tooltip')).find(t => (t.textContent || '').includes('Nueva Relación'));
  if (!addBtn || !tip) return;

  const tipWrap = tip.closest('.cdk-overlay-connected-position-bounding-box');
  if (tipWrap) {
    tipWrap.style.left = '0px';
    tipWrap.style.top = '0px';
    tipWrap.style.width = '100vw';
    tipWrap.style.height = '100vh';
    tipWrap.style.position = 'fixed';
    tipWrap.style.display = 'block';
  }

  tip.style.position = 'fixed';
  tip.style.margin = '0';
  tip.style.transform = 'none';

  const br = addBtn.getBoundingClientRect();
  const tr = tip.getBoundingClientRect();
  const left = Math.max(8, Math.round(br.left + (br.width / 2) - (tr.width / 2)));
  const top = Math.round(br.bottom + 10);

  tip.style.left = `${left}px`;
  tip.style.top = `${top}px`;
}
